previewCss:
.darma-loader-darma-custom-579 {color: var(--loader-color, #be123c);
  --loader-secondary-color: #fda4af;
  --loader-bg: #ffffff;
   width:30px;
   aspect-ratio: 1;
   background: var(--loader-color, #be123c);
   display: grid;
   transform-origin: top right;
   animation: darma-loader-darma-custom-579-l6-0 1s infinite linear;
}
.darma-loader-darma-custom-579::before, .darma-loader-darma-custom-579::after  {
  content: "";
   grid-area: 1/1;
   background: var(--loader-color, #be123c);
   transform-origin: inherit;
   animation: inherit;
   animation-name: darma-loader-darma-custom-579-l6-1;
}
.darma-loader-darma-custom-579::after  {
  background:var(--loader-color, #be123c);
   --s:180deg;
}
@keyframes darma-loader-darma-custom-579-l6-0  {
  70%, 100% {transform: rotate(360deg)}
}
@keyframes darma-loader-darma-custom-579-l6-1  {
  30% {transform: rotate(var(--s,90deg))}
70% {transform: rotate(0)}
}

